// To parse this JSON data, do
//
//     final tsconfig = tsconfigFromJson(jsonString);

import 'dart:convert';

Tsconfig tsconfigFromJson(String str) => Tsconfig.fromJson(json.decode(str));

String tsconfigToJson(Tsconfig data) => json.encode(data.toJson());

class Tsconfig {
    String tsconfigExtends;

    Tsconfig({
        required this.tsconfigExtends,
    });

    factory Tsconfig.fromJson(Map<String, dynamic> json) => Tsconfig(
        tsconfigExtends: json["extends"],
    );

    Map<String, dynamic> toJson() => {
        "extends": tsconfigExtends,
    };
}
